import React from 'react'
import styles from './nav-bar.module.css';
import NavButton from '../nav-button';

const NavBar = () => {
  const [activeDropdown, setActiveDropdown] = useState("");

  function toggleDropdown(openDropdown) {
    let option =
      activeDropdown === openDropdown
        ? setActiveDropdown("")
        : setActiveDropdown(openDropdown);
  }

  const obj1 = {
    title: "Foods",
    content: ["Placeholder", "Placeholder", "Placeholder"],
  };

  const dropDownObjectEx = [obj1, obj1, obj1, obj1];

  const obj2 = {
    title: "Products",
    content: ["Something", "Something", "Something"],
  };
  const dropDownObjectEx2 = [obj2, obj2, obj2, obj2];

  return (
    <div className={styles.nav__bar}>
        <NavButton text="Discovery" imgSrc="/images/ChevronDown.png" />
        <NavButton text="About" imgSrc="/images/ChevronDown.png" />
        <NavButton text="Contact us"  />
    </div>
  )
}

export default NavBar;


